from decimal import Decimal, InvalidOperation, ROUND_HALF_UP

def parse_monto(raw):
    s = str(raw).strip().replace(',', '.')
    try:
        val = Decimal(s)
    except (InvalidOperation, TypeError) as e:
        raise ValueError(f"monto no parseable: {raw!r}") from e
    if not val.is_finite():
        raise ValueError(f"monto no finito: {raw!r}")
    if val < 0:
        raise ValueError(f"monto negativo: {val}")
    return val.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)

for v in ["10.5", "3,25", "abc", "-1"]:
    try:
        print(v, "->", parse_monto(v))
    except ValueError as e:
        print(v, "ERR", e)

class DataLoadError(Exception):
    pass

def load_text(path_fn):
    try:
        return path_fn()
    except OSError as e:
        raise DataLoadError(f"no se pudo cargar: {e}") from e

def bad_reader():
    raise OSError("no such file: data/clientes.csv")

try:
    load_text(bad_reader)
except DataLoadError as e:
    print(type(e).__name__, e)
    print(type(e.__cause__).__name__, e.__cause__)

state = {"closed": False}

def work(fail: bool):
    try:
        if fail:
            raise RuntimeError("boom")
        return "ok"
    finally:
        state["closed"] = True

print(work(False), state)
try:
    work(True)
except RuntimeError:
    print("err", state)

def parse_or_default(raw, default=0):
    try:
        return int(raw)
    except (TypeError, ValueError):
        return default

print(parse_or_default("10"), parse_or_default("x"))

def run_job(cfg):
    if not cfg.get("delimiter"):
        raise RuntimeError("fail-fast: delimiter vacío en config")
    return "ok"

try:
    print(run_job({"delimiter": ","}))
    print(run_job({"delimiter": ""}))
except RuntimeError as e:
    print(e)

def mask_email(e: str) -> str:
    if '@' not in e:
        return '***'
    user, dom = e.split('@', 1)
    if not user:
        return f'***@{dom}'
    return f'{user[0]}***@{dom}'

print(mask_email('ana@ejemplo.pe'))

def classify_error(exc):
    if isinstance(exc, TimeoutError):
        return "retry"
    if isinstance(exc, ValueError):
        return "no_retry"
    return "no_retry"

print(classify_error(TimeoutError()))
print(classify_error(ValueError('bad')))

import time

def with_backoff(attempts=3):
    delay = 0.01
    for i in range(attempts):
        try:
            if i < 2:
                raise TimeoutError("net")
            return "ok"
        except TimeoutError:
            time.sleep(delay)
            delay *= 2
    raise TimeoutError("exhausted")

print(with_backoff())

