class PipelineError(Exception):
    pass

def step(x):
    if x < 0:
        raise PipelineError("neg")
    return x

print(step(1))
try:
    step(-1)
except PipelineError as e:
    print(type(e).__name__, e)

def guard_cfg(cfg):
    if cfg.get("path") in (None, ""):
        raise RuntimeError("fail-fast config path")
    return True

print(guard_cfg({"path": "data.csv"}))

def mask_phone(p: str) -> str:
    digits = ''.join(ch for ch in p if ch.isdigit())
    if len(digits) < 4:
        return '***'
    return '*' * (len(digits) - 4) + digits[-4:]

print(mask_phone('999111222'))
